            'description': 'Three identical W605 tokens'
        },

        # Existing single token test case
        {
            'input': "escape = '\\.jpg'\n",
            'expected': "escape = r'\\.jpg'\n",
            'description': 'Single W605 token'
        },

        # Different tokens
        {
            'input': "x = ('\\.first', '\\n.second')\n",
            'expected': "x = (r'\\.first', '\\n.second')\n",
            'description': 'Mixed valid/invalid escapes'
        },

        # Raw strings (should not change)
        {
            'input': "x = r'\\.raw'\n",
            'expected': "x = r'\\.raw'\n",
            'description': 'Raw string with invalid escape'
        },

        # Valid escape sequences (should not change)
        {
            'input': "x = '\\n.valid'\n",
            'expected': "x = '\\n.valid'\n",
            'description': 'Valid escape sequence'
        },

        # Triple quoted strings
        {
            'input': 'text = """\\.invalid""" + """\\.invalid"""\n',
            'expected': 'text = r"""\\.invalid""" + r"""\\.invalid"""\n',
            'description': 'Triple quoted identical strings'
        },

        # Mixed quote types
        {
            'input': "mixed = ('\\.single', \"\\.double\")\n",
            'expected': "mixed = (r'\\.single', r\"\\.double\")\n",
            'description': 'Mixed quote types with identical invalid escapes'
        }
    ]

    options = autopep8.parse_args(['--aggressive', '-'])

    all_passed = True
    for i, test_case in enumerate(test_cases, 1):
        input_code = test_case['input']
        expected = test_case['expected']
        description = test_case['description']

        try:
            result = autopep8.fix_code(input_code, options=options)

            if result == expected:
                print(f"✓ Test {i} PASSED: {description}")
